import "../styles/Team.css";
import { FaLinkedin, FaGithub } from "react-icons/fa";

const teamMembers = [
  { name: "Anupam Sanfui", role: "Cyber Security Analyst", imgSrc: "/images/anupam.jpg", linkedin: "#", github: "#" },
  { name: "Sayan Maity", role: "Advanced Data Analytics & ML Intern", imgSrc: "/images/sayan.jpg", linkedin: "#", github: "#" },
  { name: "Rupankar Garai", role: "Freelancer | Intern at Edunet", imgSrc: "/images/rupankar.jpg", linkedin: "#", github: "#" },
  { name: "Anisha Roy", role: "UI/UX Designer", imgSrc: "/images/anisha.jpg", linkedin: "#" },
  { name: "Dev Sharma", role: "DevOps Engineer", imgSrc: "/images/dev.jpg", linkedin: "#" },
  { name: "Sneha Gupta", role: "Full Stack Developer", imgSrc: "/images/sneha.jpg", linkedin: "#" },
  { name: "Ravi Singh", role: "AI/ML Intern", imgSrc: "/images/ravi.jpg", linkedin: "#", github: "#" },
  { name: "Megha Kapoor", role: "Marketing Head", imgSrc: "/images/megha.jpg", linkedin: "#" },
  { name: "Ishaan Verma", role: "Product Manager", imgSrc: "/images/ishaan.jpg", linkedin: "#" },
];

export default function Team() {
  return (
    <section className="team-section">
      <h2>Our Team</h2>
      <p>
        Meet our talented team of professionals dedicated to delivering exceptional solutions.
      </p>

      <div className="team-carousel">
        {teamMembers.map((member, idx) => (
          <div className="team-card" key={idx}>
            <div className="image-container">
              <img src={member.imgSrc} alt={member.name} />
            </div>
            <h3>{member.name}</h3>
            <p className="role">{member.role}</p>
            <div className="social-icons">
              {member.linkedin && (
                <a href={member.linkedin} target="_blank" rel="noopener noreferrer">
                  <FaLinkedin />
                </a>
              )}
              {member.github && (
                <a href={member.github} target="_blank" rel="noopener noreferrer">
                  <FaGithub />
                </a>
              )}
            </div>
          </div>
        ))}
      </div>

  
    </section>
  );
}
